parameter WIDTH = 1
)(
input       src_clk,
input       rst_n,
input       src_pulse,    // 单脉冲
input       dst_clk,
output reg  dst_pulse     // 目标域脉冲
);
// 源域：翻转触发器
reg src_toggle;
always @(posedge src_clk or negedge rst_n) begin
if (!rst_n) src_toggle <= 1'b0;
else if (src_pulse) src_toggle <= ~src_toggle;
end
// 目的域：双触发器 + 边沿检测
(* ASYNC_REG = "TRUE" *) reg [1:0] dst_sync;
reg dst_toggle_dly;
always @(posedge dst_clk or negedge rst_n) begin
if (!rst_n) {dst_sync, dst_toggle_dly} <= 3'b0;
else        {dst_sync, dst_toggle_dly} <= {src_toggl

e, dst_sync};
end
wire toggle_edge = dst_sync[1] ^ dst_toggle_dly;
always @(posedge dst_clk or negedge rst_n) begin
if (!rst_n) dst_pulse <= 1'b0;
else        dst_pulse <= toggle_edge;
endendmodule
关键点：
src_pulse 必须单周期有效，否则需加握手机制；
目的域脉冲宽度 = 1 个 dst_clk 周期；
反馈路径（可选）：将 dst_pulse 再同步回 src_clk，生成忙标志，防止新
脉冲在前一次未完成时被发送。
