3. 功耗对比（基于 28 nm、100 MHz、8 bit 寄存器阵列、信号概率 0.5、1 0000 个 DFF 规模）： 同步使能：时钟树 100 % 翻转，αclk=1，Pdyn_clk ≈ 3.2 mW；数据端 αdata=0.25，Pdyn_data ≈ 0.8 mW；总动态功耗 4.0 mW。 门控时钟：en 有效占空比 25 %，αclk=0.25，Pdyn_clk ≈ 0.8 mW；IC G cell 额外 leakage 约 0.02 mW；总动态功耗 0.82 mW。 节省比例：(4.0 – 0.82)/4.0 ≈ 79 % 时钟网络功耗下降，整体功耗下降约 30 %（含数据端与 memory）。 面积代价：每 8 个 DFF 共享 1 个 ICG，面积增加 <1 %；但需额外 hold buffer 约 2 %。

示例：32 周期迭代乘法器（高基 Booth-Wallace 树） RTL（可综合）：

```systemverilog
module mul_mcp #(
parameter WIDTH = 32
)(
input               clk,
input               rst_n,
input               start,          // 高电平启动一次乘法
input  [WIDTH-1:0]  a, b,
output              done,
output [2*WIDTH-1:0] product

);
reg [5:0] cnt;           // 0~31 计数器
reg       busy;          // 运算中标志
always @(posedge clk or negedge rst_n) begin
if (!rst_n) begin
busy <= 0;
cnt  <= 0;
end
else if (start && !busy) begin
busy <= 1;
cnt  <= 0;
end
else if (busy) begin
if (cnt == 31) begin
busy <= 0;
end
cnt <= cnt + 1;
endend
// 例化组合乘法阵列，组合逻辑深度约 32 级
wire [2*WIDTH-1:0] comb_product = booth_wallace(a, b);
reg  [2*WIDTH-1:0] product_reg;
always @(posedge clk) begin
if (busy && cnt == 31)
product_reg <= comb_product;  // 第 32 个周期才采样
end
assign product = product_reg;
assign done    = busy && (cnt == 31);
endmodule
```

为什么必须设 MCP 组合乘法阵列从输入寄存器 a_reg/b_reg 到 product_reg 的组合延迟约 30 n s，而时钟仅 10 ns（100 MHz）。功能上，控制逻辑保证第 32 个周期才采样， 因此建立检查应放松到 32 周期；否则综合工具会拼命插缓冲器/高驱动单元， 面积爆炸。 对应 SDC（国内 DC/PT 通用） # 先定义时钟 create_clock -name CLK -period 10 [get_ports clk] # 约束乘法路径 set_multicycle_path 32 -setup -from [get_cells a_reg] -to [g et_cells product_reg] set_multicycle_path 31 -hold  -from [get_cells a_reg] -to [g et_cells product_reg] 关键点：
-hold 用 31，确保 PT 检查的是 31 周期前的沿，不会错报 hold；

若设计含时钟使能，需加 -through [get_pins busy] 做更精细限定，防止误伤其他路径。

以下给出完整可综合 RTL，状态机采用 one-hot 编码，三段式写法，已在 Xili nx Vivado 2023.1 通过 lint 与综合。协议要求：检测到 0x55→0xAA→0x66 且 valid&ready 同时为高时，输出单周期 match 脉冲。 Moore 版本

```systemverilog
module proto_moore (
input        clk,
input        rst_n,
input        valid,
input        ready,
input  [7:0] data_in,
output       match
);
localparam IDLE = 3'b001;
localparam S55  = 3'b010;
localparam SAA  = 3'b100;
reg [2:0] state, nxt;
reg       match_r;
// 三段式第一段：时序状态寄存器
always @(posedge clk or negedge rst_n) begin
if (!rst_n) state <= IDLE;
else        state <= nxt;
end
// 三段式第二段：组合逻辑下一状态
always @(*) begin
nxt = state;
case (state)
IDLE : if (valid & ready & data_in==8'h55) nxt = S55;
else                                  nxt = IDLE;
S55  : if (valid & ready & data_in==8'hAA) nxt = SAA;
else if (valid & ready)              nxt = IDLE;
SAA  : if (valid & ready)                   nxt = IDLE;
else                                  nxt = SAA;
default : nxt = IDLE;
endcaseend
// 三段式第三段：Moore 输出仅与 state 有关
always @(*) begin
match_r = 1'b0;
case (state)
SAA : if (valid & ready & data_in==8'h66) match_r = 1'b1;
default : match_r = 1'b0;
endcaseend
// 输出寄存器打拍，保证时序
reg match_q;

always @(posedge clk or negedge rst_n) begin
if (!rst_n) match_q <= 1'b0;
else        match_q <= match_r;
end
assign match = match_q;
endmodule
```

Mealy 版本

```systemverilog
module proto_mealy (
input        clk,
input        rst_n,
input        valid,
input        ready,
input  [7:0] data_in,
output       match
);
localparam IDLE = 2'b01;
localparam S55  = 2'b10;
reg [1:0] state, nxt;
reg       match_r;
// 时序状态寄存器
always @(posedge clk or negedge rst_n) begin
if (!rst_n) state <= IDLE;
else        state <= nxt;
end
// 组合下一状态
always @(*) begin
nxt = state;
case (state)
IDLE : if (valid & ready & data_in==8'h55) nxt = S55;
else                                  nxt = IDLE;
S55  : if (valid & ready & data_in==8'hAA) nxt = IDLE;
else if (valid & ready)              nxt = IDLE;
default : nxt = IDLE;
endcaseend
// Mealy 输出与 state+输入 有关
always @(*) begin
match_r = 1'b0;
case (state)
S55 : if (valid & ready & data_in==8'h66) match_r = 1'b1;
default : match_r = 1'b0;
endcaseend
// 输出寄存器打拍，消除毛刺

reg match_q;
always @(posedge clk or negedge rst_n) begin
if (!rst_n) match_q <= 1'b0;
else        match_q <= match_r;
end
assign match = match_q;
endmodule
```

关键差异： Moore 需要 3 个状态，输出在 SAA 状态且数据为 0x66 时拉高； Mealy 仅需 2 个状态，利用“状态+输入”组合，在 S55 状态且数据为 0x6 6 时立即拉高，节省一级状态寄存器，但输出逻辑多一级组合。

以下示例采用三段式、one-hot 编码、异步复位、同步释放，default 分支明确回到 IDLE，可直接综合为 FPGA/ASIC 网表。

```systemverilog
module fsm_safe (
input  wire        clk,
input  wire        rst_n,   // 低有效异步复位
input  wire        req,
output reg         ack
);
// 1. 状态编码（one-hot，国内主流风格）
localparam IDLE = 3'b001;
localparam WAIT = 3'b010;
localparam DONE = 3'b100;
reg [2:0] state, next;
// 2. 时序逻辑：状态寄存器 + 异步复位、同步释放

always @(posedge clk or negedge rst_n) begin
if (!rst_n)
state <= IDLE;
else
state <= next;
end
// 3. 组合逻辑：次态译码，带 default 回到 IDLE
always @(*) begin
next = state;           // 防止锁死，先赋默认值
case (state)
IDLE: next = req ? WAIT : IDLE;
WAIT: next = (req) ? WAIT : DONE;
DONE: next = IDLE;  // 单周期脉冲，立即回 IDLE
**default: next = IDLE;** // 任何非法态下一拍回到 IDLEendcaseend
// 4. 输出逻辑：Moore 型，同步输出
always @(posedge clk or negedge rst_n) begin
if (!rst_n)
ack <= 1'b0;
else
ack <= (state == DONE);
endendmodule
关键细节：
default 放在 case 末尾，综合后不会生成额外优先级逻辑；
next 先赋默认值，避免隐式 latch；
复位值与 default 次态均为 IDLE，保证上电或跑飞后系统可自恢复。
```

以下给出一个可综合的 2×2 路由器节点 RTL 及配套 SVA，演示如何在 Jasper Gold 2022.09 上完成无死锁证明。代码可直接在国产麒麟服务器跑通，工具脚

本同时兼容 VC-Formal。 步骤 1：RTL 片段（仅保留关键信号）

```systemverilog
module node #(
parameter DW = 32
)(
input  logic        clk,
input  logic        rst_n,
output logic [1:0]  req_o,   // 向两个邻居发请求
input  logic [1:0]  gnt_i,   // 邻居返回授权
output logic [DW-1:0] data_o,
output logic        valid_o,
input  logic        ready_i
);
logic [1:0]         req, gnt;
logic               has_token;
// 简化 token 协议：只有拿到 token 才能发数据
assign req_o = req;
always_ff @(posedge clk or negedge rst_n) begin
if (!rst_n) begin
req   <= '0;
has_token <= 1'b1;  // 上电默认拥有 tokenend
else begin
// 仲裁：若拿到任意授权，释放 token
if (|gnt_i) has_token <= 1'b0;
// 若上游 ready 且本节点有 token，可发数据
if (ready_i && has_token) begin
valid_o <= 1'b1;
req     <= 2'b00;            // 不再请求
end
else if (!has_token) begin
// 无 token 时循环请求，直到拿到授权
req <= 2'b11;
endendendendmodule
步骤 2：SVA 无死断属性
bind node assert_node_deadlock_free (
// 关键：定义“最终必退出请求状态”
assert property (
@(posedge clk) disable iff (!rst_n)
(|req_o) |-> s_eventually (!req_o)
) else $fatal(0, "Liveness failed: node deadlock");
// 覆盖属性：确保 token 曾经离开本节点
cover property (
@(posedge clk) disable iff (!rst_n)

s_eventually (!has_token)
);
);
