下面给出可综合的 Verilog 模板，采用 (72,64) SEC-DED 汉明码，状态寄存器 16 bit，纠正周期 1 clock，面积代价约 +18% 寄存器 +6% 组合逻辑，符合国内 28 nm 工艺 200 MHz 要求。

```systemverilog
module fsm_ecc #(
parameter STATE_W  = 16,
parameter ECC_W    = 5          // 2^5 >= 16+5+1，满足汉明
不等式
)(
input  wire                clk,
input  wire                rst_n,
input  wire                state_en,
input  wire [STATE_W-1:0]  state_in,
output reg  [STATE_W-1:0]  state_out,
output wire                single_err,
output wire                double_err,
output wire                scrub_done
);
// 1. 状态 + 校验 拼接寄存器
localparam TOTAL_W = STATE_W + ECC_W;
reg [TOTAL_W-1:0] r_data;
// 2. 组合逻辑：计算 ECC 校验位
wire [ECC_W-1:0] ecc_calc;
assign ecc_calc = calc_hamming(state_in);
function [ECC_W-1:0] calc_hamming;
input [STATE_W-1:0] d;
integer i, j;
begin
for (j = 0; j < ECC_W; j = j+1) begin
calc_hamming[j] = 1'b0;
for (i = 0; i < STATE_W; i = i+1)
if (i & (1<<j)) calc_hamming[j] = calc_hammi
ng[j] ^ d[i];
endendendfunction
// 3. 写路径：正常更新
wire [TOTAL_W-1:0] data_in = {state_in, ecc_calc};
always @(posedge clk or negedge rst_n) begin
if (!rst_n)      r_data <= {STATE_W+ECC_W{1'b0}};
else if (state_en) r_data <= data_in;
end
// 4. 读路径：在线检错纠正
wire [ECC_W-1:0] ecc_reg = r_data[ECC_W-1:0];
wire [STATE_W-1:0] state_reg = r_data[STATE_W+ECC_W-1:ECC_
W];
wire [ECC_W-1:0] ecc_syn;
wire [STATE_W-1:0] state_cor;
assign ecc_syn  = calc_hamming(state_reg) ^ ecc_reg;
assign state_cor = (single_err && !double_err) ? state_reg ^
(1<<syn2bit(ecc_syn)) : state_reg;
function integer syn2bit;
input [ECC_W-1:0] s;

begin syn2bit = 0; for (integer k = 0; k < ECC_W; k=k+1)
if (s[k]) syn2bit = syn2bit | (1<<k); endendfunction
assign single_err = (^ecc_syn) && (ecc_syn != 0);  // 奇数个1
assign double_err = !(^ecc_syn) && (ecc_syn != 0); // 偶数个1
非0
always @(posedge clk) state_out <= state_cor;
// 5. 离线 scrubbing 接口（可选）
assign scrub_done = 1'b0; // 占位，实际可定时回读纠正
endmodule
```

关键点说明单错纠正立即完成，状态机无需停顿；双错拉高 double_err，由顶层安全 FSM 强制进入 SAFE 状态。 ECC 计算函数纯组合，综合后自动映射为 XOR 树，关键路径仅 2 级 LU T，满足 200 MHz。 寄存器位宽膨胀 31%，但 16 bit 状态本身很小，面积代价可接受；若状态位宽 >32，建议改用 (39,32) 缩短汉明码 并做流水线 ECC。
形式验证脚本（Synopsys VC Formal）需加入 assert property (##
1 state_out == exp_state)，确保单 bit 翻转注入后下一周期恢
复。

// 可综合 RTL，两层 HSM 示例：I2C 主控顶层 + 字节传输子层

```systemverilog
module i2c_master_hsm #(
parameter FCLK_HZ = 100_000_000,
parameter SCL_HZ  = 400_000
)(
input  logic        clk,
input  logic        rst_n,        // 异步复位，同步释放
input  logic        start,
input  logic [6:0]  dev_addr,
input  logic        rw_bit,
output logic        done,
output logic        ack_err,
// 物理层
output logic        scl_o,
inout               sda_io
);
// 1. 主层状态定义
typedef enum bit [2:0] {
M_IDLE   = 3'b000,
M_START  = 3'b001,
M_ADDR   = 3'b010,
M_DATA   = 3'b011,
M_STOP   = 3'b100,
M_DONE   = 3'b101
} state_m_e;
// 2. 子层状态定义
typedef enum bit [1:0] {
S_IDLE   = 2'b00,
S_SHIFT  = 2'b01,
S_ACK    = 2'b10,
S_DONE   = 2'b11
} state_s_e;
// 3. 打包子层控制向量
typedef struct packed {
logic       en;
logic [7:0] data;
logic       rw;
} sub_cmd_t;
typedef struct packed {
logic       done;
logic       ack;
logic [7:0] data;
} sub_resp_t;
// 4. 状态寄存器
state_m_e   state_m_r, state_m_nxt;
state_s_e   state_s_r, state_s_nxt;
// 5. 子层信号
sub_cmd_t   sub_cmd;
sub_resp_t  sub_resp;

// 6. 主层 FSM
always_ff @(posedge clk or negedge rst_n) begin
if (!rst_n)  state_m_r <= M_IDLE;
else         state_m_r <= state_m_nxt;
end
always_comb begin
state_m_nxt = state_m_r;
sub_cmd.en   = 1'b0;
sub_cmd.data = '0;
sub_cmd.rw   = rw_bit;
done         = 1'b0;
ack_err      = 1'b0;
unique case (state_m_r)
M_IDLE: if (start) state_m_nxt = M_START;
M_START: begin
sub_cmd.en = 1'b1;
if (sub_resp.done) state_m_nxt = M_ADDR;
end
M_ADDR: begin
sub_cmd.en   = 1'b1;
sub_cmd.data = {dev_addr, rw_bit};
if (sub_resp.done) begin
if (sub_resp.ack) state_m_nxt = M_DATA;
else              state_m_nxt = M_DONE;
endend
M_DATA: begin
sub_cmd.en = 1'b1;
if (sub_resp.done) begin
ack_err = !sub_resp.ack;
state_m_nxt = M_STOP;
endend
M_STOP: begin
sub_cmd.en = 1'b1;
if (sub_resp.done) state_m_nxt = M_DONE;
end
M_DONE: begin
done = 1'b1;
state_m_nxt = M_IDLE;
end
default: state_m_nxt = M_IDLE;
endcaseend
// 7. 子层 FSM（字节+ACK 位传输）
always_ff @(posedge clk or negedge rst_n) begin
if (!rst_n)  state_s_r <= S_IDLE;
else         state_s_r <= state_s_nxt;
end
always_comb begin
state_s_nxt = state_s_r;
sub_resp.done = 1'b0;
sub_resp.ack  = 1'b0;
sub_resp.data = '0;

unique case (state_s_r)
S_IDLE: if (sub_cmd.en) state_s_nxt = S_SHIFT;
S_SHIFT: begin
// 简化：假设已移位 8 次
state_s_nxt = S_ACK;
end
S_ACK: begin
sub_resp.ack = 1'b1;  // 假设收到 ACK
state_s_nxt  = S_DONE;
end
S_DONE: begin
sub_resp.done = 1'b1;
if (!sub_cmd.en) state_s_nxt = S_IDLE;
end
default: state_s_nxt = S_IDLE;
endcaseend
// 8. 物理层省略
assign scl_o = 1'b0;
assign sda_io = 1'bz;
endmodule
```

关键技巧： enum 状态必须覆盖全部情况，unique case 让仿真在重复编码时立即报错； struct 采用 packed 方式，可直接 assign status_vec = {sub_res p} 用于调试探针； 子层 done 信号只拉高一个周期，主层在检测到 done 后立即跳转，避免回环； 面试时主动说明：若子层时钟不同，需将 sub_cmd 与 sub_resp 经过异步 FIFO 或 Gray 同步，否则综合后会出现 CDC 警告。

给出可综合、可复用的 RTL 模板（单时钟域示例）： // 父状态机

```systemverilog
module parent_fsm (
input        clk,
input        rst_n,
output reg   parent_vld,      // 告知子状态机：父状态已稳定
output reg [2:0] parent_state // 父当前状态编码
);
localparam S_IDLE = 3'd0;
localparam S_WORK = 3'd1;
reg [2:0] state, next;
always @(*) begin

next = state;
case (state)
S_IDLE : next = start ? S_WORK : S_IDLE;
S_WORK : next = done  ? S_IDLE : S_WORK;
endcaseend
always @(posedge clk or negedge rst_n) begin
if (!rst_n) begin
state <= S_IDLE;
parent_state <= S_IDLE;
parent_vld   <= 1'b0;
end else begin
state <= next;
parent_state <= next;   // 寄存输出
parent_vld   <= 1'b1;   // 状态稳定后拉高
endendendmodule
// 子状态机
module child_fsm (
input        clk,
input        rst_n,
input        parent_vld,
input [2:0]  parent_state,
output reg   child_done
);
localparam S_C0 = 2'd0;
localparam S_C1 = 2'd1;
reg [1:0] cstate, nstate;
always @(*) begin
nstate = cstate;
child_done = 1'b0;
if (parent_vld && parent_state == 3'd1) begin
case (cstate)
S_C0 : nstate = S_C1;
S_C1 : begin
child_done = 1'b1;
nstate = S_C0;
endendcase
end else begin
nstate = S_C0;  // 父状态不满足时回到初始子状态
endend
always @(posedge clk or negedge rst_n) begin
if (!rst_n) cstate <= S_C0;
else        cstate <= nstate;
endendmodule
关键要点：
parent_state 与 parent_vld 都经过寄存器输出，子状态机只在 parent_
vld==1 时才采样，彻底消除毛刺。

子状态机内部不依赖组合逻辑译码，避免综合后产生 latch。
若子状态机与父状态机不在同一时钟域，必须把 parent_vld 与 paren
t_state 分别做两级触发器同步，并在约束文件里设 set_clock_grou
ps -async。
```

步骤一：在 hsm_env 中例化专用覆盖率组件
hsm_coverage cov_h;
cov_h = hsm_coverage::type_id::create("cov_h", this);
步骤二：定义 hsm_transaction 级 covergroup covergroup hsm_crypto_cg with function sample(hsm_transactio
n tr);
