endfunction
步骤四：对 寄存器事件 补充覆盖
covergroup hsm_reg_cg;
key_slot_wr : coverpoint `HSM_KEY_SLOT {
bins slot0 = {0};
bins slot15 = {15};
bins others = {[1:14]};
}
lock_flag : coverpoint `HSM_LOCK {
