logic [AW:0] wr_ptr, rd_ptr;          // 多1位，MSB用于绕回标志
logic [AW:0] wr_ptr_g, rd_ptr_g;
logic [AW:0] wr_ptr_g_sync, rd_ptr_g_sync;
// 格雷码转换
assign wr_ptr_g = wr_ptr ^ (wr_ptr >> 1);
assign rd_ptr_g = rd_ptr ^ (rd_ptr >> 1);
// 双寄存器同步链
always_ff @(posedge wr_clk or negedge wr_rst_n) begin
if (!wr_rst_n) {rd_ptr_g_sync, rd_ptr_g_sync2} <= '0;
else           {rd_ptr_g_sync, rd_ptr_g_sync2} <= {rd_pt
r_g_sync2, rd_ptr_g};
end
always_ff @(posedge rd_clk or negedge rd_rst_n) begin
if (!rd_rst_n) {wr_ptr_g_sync, wr_ptr_g_sync2} <= '0;
else           {wr_ptr_g_sync, wr_ptr_g_sync2} <= {wr_pt
r_g_sync2, wr_ptr_g};
end // 空满判断
assign empty = (wr_ptr_g_sync[AW:0] == rd_ptr_g);
assign full  = ({~wr_ptr[AW], wr_ptr[AW-1:0]} == rd_ptr_g_sy
nc[AW:0]);
// 省略RAM、指针递增、格雷码逆转换，面试时口述
endmodule
要点： 指针多1位，MSB作为绕回标志； 空满判断只比较格雷码，单bit翻转保证亚稳态概率可忽略； 深度必须2^n，否则高位比较失效； 同步链禁止带任何组合逻辑，否则MTBF 暴跌。

以下代码给出参数化位宽、可综合、无锁存、已留约束接口的完整 RTL，可直接用于 40 nm 工艺或 Xilinx/Intel FPGA。 重点信号已用中文注释标明，方便面试时快速讲解。 // 格雷码指针跨时钟域模块 // 功能：把 n-bit 二进制指针转成格雷码，经两级同步传到对向时钟域

```systemverilog
module cdc_gray_ptr #(
parameter PTR_W = 4    // 用户可改，真实 FIFO 深度=2^(PTR_W-1)
)(

// 源时钟域
input                src_clk,
input                src_rst_n,
input        [PTR_W-1:0] src_bin_ptr,   // 二进制指针，已寄
存
output logic [PTR_W-1:0] src_gray_ptr,  // 格雷码指针，本时
钟域使用
// 目的时钟域
input                dst_clk,
input                dst_rst_n,
output logic [PTR_W-1:0] dst_gray_ptr   // 同步后的格雷码指
针
);
//-------------------------- 源时钟域：二进制 → 格雷码 --------
------------------//
always_ff @(posedge src_clk or negedge src_rst_n) begin
if (!src_rst_n)
src_gray_ptr <= '0;
else
src_gray_ptr <= src_bin_ptr ^ (src_bin_ptr >> 1);
// **格雷码转换**
end
//-------------------------- 目的时钟域：两级同步器 ------------
--------------//
logic [PTR_W-1:0] gray_d1, gray_d2;
always_ff @(posedge dst_clk or negedge dst_rst_n) begin
if (!dst_rst_n) begin
gray_d1 <= '0;
gray_d2 <= '0;
end else begin
gray_d1 <= src_gray_ptr;  // **第一拍**
gray_d2 <= gray_d1;       // **第二拍**
endend
assign dst_gray_ptr = gray_d2;
endmodule
```

