input  wire                    ana_clk,   // 模拟时钟（与
pclk 异步）
input  wire                    ana_rst_n
);
//-------------------------------------------
// 寄存器定义
//-------------------------------------------
reg [31:0] reg_ctl;      // 31:lock 30:upd  4:0 lvl
wire       reg_sel = psel && (paddr[11:0] == 12'h000);
wire       reg_wr  = reg_sel && pwrite && penable && !reg_ct
l[31];
wire       reg_rd  = reg_sel && !pwrite;
//-------------------------------------------
// APB 写通道
//-------------------------------------------
always @(posedge pclk or negedge presetn) begin
if (!presetn) begin
reg_ctl <= 32'h0;
end
else if (reg_wr) begin
reg_ctl[4:0]  <= pwdata[4:0];
reg_ctl[30]   <= 1'b1;          // 置更新标志
if (pwdata[31]) reg_ctl[31] <= 1'b1; // 写锁定位
end
else if (reg_rd) begin
reg_ctl[30] <= 1'b0;            // 读清
endend
//-------------------------------------------
// APB 读通道
//-------------------------------------------
always @(posedge pclk or negedge presetn) begin
if (!presetn) begin
prdata <= 32'h0;

end
else if (reg_rd) begin
prdata <= reg_ctl;
endend
// 简化：单周期 ready，无 wait
always @(posedge pclk or negedge presetn) begin
if (!presetn) pready <= 1'b0;
else          pready <= reg_sel && penable;
end
// 错误响应：越界或已锁定仍写
assign pslverr = reg_wr && (pwdata[4:0] > 5'd29 || reg_ctl[3
1]);
//-------------------------------------------
// CDC：pclk → ana_clk
//-------------------------------------------
reg  [4:0]  lvl_d, lvl_q;
reg         vld_d, vld_q;
reg         ack_q1, ack_q2;
// 电平同步器
always @(posedge pclk or negedge presetn) begin
if (!presetn) begin
lvl_d <= 5'h0;
vld_d <= 1'b0;
end
else if (reg_ctl[30]) begin  // 更新标志
lvl_d <= reg_ctl[4:0];
vld_d <= 1'b1;
end
else if (ack_q2) begin       // 收到应答
vld_d <= 1'b0;
endend
// 双寄存器同步到模拟域
always @(posedge ana_clk or negedge ana_rst_n) begin
if (!ana_rst_n) begin
volt_lvl <= 5'h0;
volt_vld <= 1'b0;
ack_q1   <= 1'b0;
ack_q2   <= 1'b0;
end
else begin
ack_q1   <= volt_ack;
ack_q2   <= ack_q1;
if (vld_q && !volt_vld) begin
volt_lvl <= lvl_q;
volt_vld <= 1'b1;
end
else if (volt_ack) begin
volt_vld <= 1'b0;
endend

end
// 将 pclk 域信号同步到 ana_clk 域
always @(posedge ana_clk or negedge ana_rst_n) begin
if (!ana_rst_n) begin
lvl_q <= 5'h0;
vld_q <= 1'b0;
end
else begin
lvl_q <= lvl_d;
vld_q <= vld_d;
endendendmodule
关键说明：
写锁定位避免软件误操作；读清更新标志方便中断方式通知 CPU；
CDC 采用单向握手：vld_d→vld_q→volt_vld，应答 volt_ack 回同
步到 ack_q2 关闭脉冲；
pslverr 对非法档位与锁定后写操作立即报错，符合国内 SoC 对总线错误
可追溯的强制要求；
所有寄存器位均接入扫描链，综合脚本加 set_scan_element true；
面积优化：档位寄存器仅 5 位，lock & upd 标志与 APB 控制合并，不额
外增加 32-bit 阴影寄存器。
