综合日志摘要： “INFO: [Synth 8-3331] inferred 1 signed multiplier (16-bit × 16-bit) using DSP48E2” // 写法二：综合器推断“移位相加”结构

```systemverilog
module shift_add_csd #(
parameter WIDTH = 16
)(
input  wire signed [WIDTH-1:0] a,
output wire signed [WIDTH+5:0] p
);
// 常量 27 = 32 – 4 – 1 = 2^5 – 2^2 – 2^0，CSD 编码最优
localparam signed [WIDTH+5:0] C = 27;
// 显式拆成移位与加法，综合器不再推断乘法器
assign p = (a << 5) - (a << 2) - a;
endmodule
