// =========================================================
===
//  文件名：tb_top.sv
//  功能：基于接口的可参数化 Testbench 模板

// =========================================================
===
`timescale 1ns/1ps
parameter int DATA_W = 32;
parameter int ADDR_W = 16;
//------------------------------------------------------------
// 1. 接口定义：包含信号、clocking、modport、断言、覆盖率
//------------------------------------------------------------

```systemverilog
interface bus_if #(parameter DATA_W = 32, ADDR_W = 16)(input
bit clk);
logic               rst_n;
logic [ADDR_W-1:0]  addr;
logic [DATA_W-1:0]  wdata;
logic [DATA_W-1:0]  rdata;
logic               write;
logic               valid;
logic               ready;
// 时钟块：消除竞争
clocking cb @(posedge clk);
default input #1step output #0;
output addr, wdata, write, valid;
input  rdata, ready;
endclocking
// modport：DUT 与 TB 视角
modport DUT  (input clk, rst_n, addr, wdata, write, valid,
output rdata, ready);
modport TB   (clocking cb, output rst_n);
// 立即断言：检查 valid/ready 握手
assert property (@(posedge clk) disable iff (!rst_n)
valid && ready |=> !$isunknown(rdata))
else $fatal(0, "**ERROR**: rdata unknown after handshak
e!");
