// 2. DUT：简易 SRAM 控制器
//------------------------------------------------------------
module sram_ctrl #(
parameter DATA_W = 32,
parameter ADDR_W = 16
)(
bus_if.DUT bif
);
logic [DATA_W-1:0] mem [2**ADDR_W-1:0];
always_ff @(posedge bif.clk or negedge bif.rst_n) begin
if (!bif.rst_n) begin
bif.ready <= '0;
end else begin
bif.ready <= '1;
if (bif.valid && bif.ready) begin
if (bif.write) mem[bif.addr] <= bif.wdata;
else           bif.rdata <= mem[bif.addr];
endendendendmodule
