// 3. Testbench 顶层
//------------------------------------------------------------
module tb_top;
bit clk;
// 实例化接口：参数传递
bus_if #(.DATA_W(DATA_W), .ADDR_W(ADDR_W)) u_if(.*);
// DUT 实例
sram_ctrl #(.DATA_W(DATA_W), .ADDR_W(ADDR_W)) u_dut (.bif
(u_if));
// 时钟产生
initial begin
clk = '0;
forever #5 clk = ~clk;
end
// 激励线程
initial begin
// 1. 复位序列
u_if.rst_n = '0;
repeat(3) @(u_if.cb);
u_if.rst_n = '1;
@(u_if.cb);
// 2. 写操作
u_if.cb.write <= 1'b1;
u_if.cb.addr  <= 'h1000;
u_if.cb.wdata <= 32'hA5A5_A5A5;
u_if.cb.valid <= 1'b1;
@(u_if.cb);

while (!u_if.cb.ready) @(u_if.cb);
u_if.cb.valid <= 1'b0;
// 3. 读操作
u_if.cb.write <= 1'b0;
u_if.cb.addr  <= 'h1000;
u_if.cb.valid <= 1'b1;
@(u_if.cb);
while (!u_if.cb.ready) @(u_if.cb);
if (u_if.cb.rdata != 32'hA5A5_A5A5)
$fatal(0, "**FAIL**: read mismatch!");
u_if.cb.valid <= 1'b0;
// 4. 结束
repeat(5) @(u_if.cb);
$display("**PASS**: Test completed successfully!");
$finish;
end
// 波形转储
initial begin
$fsdbDumpfile("tb.fsdb");
$fsdbDumpvars(0, tb_top);
