步骤一：建立**“资源-请求”有向图模型** 每个主端口、从端口、FIFO 槽位都定义为资源节点； 当主设备持有资源 A 并请求 B 时，插入有向边 A→B； 用 1 位寄存器 edge_ab 标记该边是否存在。 步骤二：写**“无环”Safety 属性** // 假设最多 8 个节点，用 8×8 位矩阵编码有向边
logic [7:0] adj_matrix [8];
// 定义可传递闭包

logic [7:0] tc [8];
always_comb begin
tc = adj_matrix;
for (int k = 0; k < 8; k++)
for (int i = 0; i < 8; i++)
for (int j = 0; j < 8; j++)
tc[i][j] |= tc[i][k] & tc[k][j];
end
// Safety: 不存在节点自己可达自己 → 无环

```systemverilog
property no_deadlock;
@(posedge clk) disable iff (reset)
!(tc[0][0] || tc[1][1] || … || tc[7][7]);
endproperty
assert property (no_deadlock) else `uvm_error("DEADLOCK", "c
ycle found");
```

步骤三：给工具加合法约束仲裁器公平性：assume property (s_eventually grant[i])；
资源最终释放：assume property (req |-> s_eventually !re
q)； 用cover检查“同时占用两个资源”场景未被约束砍掉。 步骤四：跑JasperGold VC Formal（国内主流） 先BMC 40 步找反例，若找到则回传波形，定位哪条边引入循环； 再跑INCMODE + PDR，若返回**“QED: property proven”**即证明无死锁； 最后vacuity report必须为 0，否则收紧约束。 通过以上四步，即可在数学层面证明“断言不会死锁”，而非单纯仿真通过。

class axi_legal_len;
// 物理信号级随机变量 rand bit [7:0] axlen;      // 对应 AXI 通道的 AxLEN rand bit [1:0] axburst;    // FIXED/INCR/WRAP // 用户可见的传输次数
int unsigned xfer_num;

// 约束 1：WRAP 突发长度只能是 2,4,8,16
constraint wrap_c {
(axburst == 2'b10) -> axlen inside {8'd1, 8'd3, 8'd
7, 8'd15};
}
// 约束 2：非 WRAP 时长度 1~256（编码 0~255）
constraint other_c {
(axburst != 2'b10) -> axlen inside {[0:255]};
}
// 约束 3：FIXED 突发建议限制在 16 拍以内（多数 IP 不支持过长）
constraint fixed_c {
(axburst == 2'b00) -> axlen inside {[0:15]};
}
// 后处理：计算传输次数
function void post_randomize();
xfer_num = axlen + 1;
// 协议断言，双重保险
if (axburst == 2'b10 && xfer_num ∉ {2,4,8,16})
$fatal(0, "WRAP burst len illegal: %0d", xfer_num);
endfunction
// 调试打印
function void print();
$display("axburst=%s axlen=%0d xfer_num=%0d",
axburst.name(), axlen, xfer_num);
endfunctionendclass // 使用示例

