以下示例目标：8 bit 输入 in 不允许出现“0xFF 后紧跟 0x00”的序列，时钟 10 0 MHz，复位低有效。 代码可直接被 Synopsys VC-Formal 或 Xilinx Vivado Formal 识别，无需修改即可综合。

```systemverilog
module top (
input        clk,
input        rst_n,
input  [7:0] in,
output [7:0] out
);
// 正常功能逻辑
assign out = in + 8'd1;
// ---------------- 约束：排除非法序列 ----------------

// 1. 定义过去值寄存器
reg [7:0] in_q;
always @(posedge clk or negedge rst_n)
if (!rst_n) in_q <= 8'h00;
else        in_q <= in;
// 2. 用 assume 禁止非法序列
property no_ff_00;
@(posedge clk) disable iff (!rst_n)
(in_q == 8'hFF) |-> (in != 8'h00);
endproperty
// 3. 关键：使用 assume 而非 assert
assume property (no_ff_00);
endmodule
```

关键点说明 assume property 告诉形式工具“该序列永不到达”，综合时工具会把对应路径剪枝，不会生成额外逻辑。 disable iff (!rst_n) 保证复位期间不检查，避免虚假违例。 若团队仍使用 Verilog-95，可用 vendor pragma 包裹：// synopsys assume (no_ff_00); 达到同样效果。 面试时要补充：“我会把该 assume 写在单独 sva 文件，顶层 bind，确保 RTL 纯净。” 这句话能体现大厂 flow 意识。

以下给出一套可直接落地的同步 valid/ready 握手完整性形式验证方案，面试时可按“思路 → 约束 → 断言 → 结果”四段作答，时间控制在 5 分钟内。
1. RTL 片段（可综合）

```systemverilog
module handshake_pipe (
input  logic        clk,
input  logic        rst_n,
input  logic [31:0] data_i,
input  logic        valid_i,
output logic        ready_o,
output logic [31:0] data_o,
output logic        valid_o,
input  logic        ready_i
);
logic [31:0] data_q;
logic        valid_q;
assign ready_o = !valid_q || ready_i;  // 背压逻辑
always_ff @(posedge clk or negedge rst_n) begin
if (!rst_n) begin
data_q  <= '0;
valid_q <= '0;
end
else if (ready_o) begin
data_q  <= data_i;
valid_q <= valid_i;
endend
assign data_o  = data_q;
assign valid_o = valid_q;
endmodule
```

2. SVA 完整性属性（单独文件 handshake_check.sv）

bind handshake_pipe handshake_assert u0(.*);

```systemverilog
module handshake_assert (
input logic clk, rst_n,
input logic [31:0] data_i, data_o,
input logic valid_i, ready_o, valid_o, ready_i
);
// 1. 无死锁：valid_i 为高且 ready_o 为低最多持续 16 周期
assume property (@(posedge clk) disable iff (!rst_n)
valid_i && !ready_o |-> ##[1:16] ready_o);
// 2. 数据不丢失：传输发生时，数据必须被下游采样
assert property (@(posedge clk) disable iff (!rst_n)
valid_o && ready_i |-> ##1 $past(data_o) == sampled_data);
// 3. 无重试溢出：valid_i 连续为高的次数不超过 8 次
assume property (@(posedge clk) disable iff (!rst_n)
valid_i [*9] |-> 0);  // 工具会报冲突，说明 RTL 已限流
// 4. 无X传播
assert property (@(posedge clk) disable iff (!rst_n)
!$isunknown({valid_o, ready_o}));
endmodule
