```systemverilog
module toggle_limiter #(
parameter DW   = 32,           // 总线宽度
parameter TH   = 4,            // 允许同时翻转上限
parameter REG  = 1             // 是否寄存输出
)(
input               clk,
input               rst_n,
input               valid_i,
input  [DW-1:0]     data_i,
output reg          ready_o,

output reg [DW-1:0] data_o
);
logic [DW-1:0] data_r;
logic [DW-1:0] toggle_mask;
logic [5:0]    toggle_cnt;       // 最大 32，6 bit 足够
logic          busy_d, busy_q;
// 计算下一拍翻转位数
assign toggle_mask = data_i ^ data_r;
assign toggle_cnt  = $countones(toggle_mask);
// 阈值比较
assign busy_d = (toggle_cnt > TH) && valid_i;
// 忙状态寄存，形成反压
always_ff @(posedge clk or negedge rst_n) begin
if (!rst_n) busy_q <= 1'b0;
else        busy_q <= busy_d;
end
// 握手：只有不忙时才更新
assign ready_o = !busy_q;
always_ff @(posedge clk or negedge rst_n) begin
if (!rst_n) begin
data_r <= '0;
end
else if (valid_i && ready_o) begin
data_r <= data_i;
endend
// 可选寄存输出，改善时序
generate
if (REG) begin
always_ff @(posedge clk) data_o <= data_r;
end else begin
always_comb data_o = data_r;
endendgenerateendmodule
关键技巧：
1. 使用 $countones 系统函数，综合工具会映射成popcount 硬核，面积
小、时序好。
2. 反压 ready_o 直接连到上游 FIFO 的读使能，无需额外协议，AXI/Hands
hake 兼容。
3. 阈值 TH 可配，综合后通过 set_toggle_limit 命令绑定到 IO 引脚，
后端可自动插入延迟单元满足 SSO。
```

