parameter CLKIN_PERIOD  = 10.0,      // 输入时钟 100 MHz
parameter MOD_RATE      = 33000,     // 33 kHz
parameter SPREAD_PCT    = 1.0        // ±1 %
)(
input        clk_i,      // 100 MHz 系统时钟
input        rst_n,
output reg   ssc_en,     // 1 开启扩频
output reg   drp_we,     // DRP write enable
output [15:0]drp_daddr,  // DRP address
output [15:0]drp_di,     // DRP data in
input        drp_rdy     // DRP ready
);
localreal  ACC_STEP = 2.0 * SPREAD_PCT / (1000.0/CLKIN_PERIO
D * 1e6/MOD_RATE);
localint   STEP_INT = int'($rtoi(ACC_STEP * 2**27));

reg [26:0] acc;
reg        tri_dir;
wire [6:0] offset = acc[26:20];        // 三角波幅值 → [-64,6
3]
wire [6:0] offset_neg = ~offset + 1;   // 负方向
wire [15:0] div_frac = 16'sd1024 + {9'b0, offset_neg}; // 默
认 1024 对应 0 ‰
always @(posedge clk_i or negedge rst_n) begin
if(!rst_n) begin
acc <= 0;
tri_dir <= 0;
end else if(ssc_en) begin
if(tri_dir)  acc <= acc - STEP_INT;
else         acc <= acc + STEP_INT;
if(acc[26])  tri_dir <= 1;       // 到达负峰值
else if(&acc[25:20]) tri_dir <= 0; // 正峰值
endend
// DRP 时序状态机，省略部分代码
localparam ADDR_DIV  = 16'h08;
always @(posedge clk_i) begin
drp_we    <= 0;
drp_daddr <= ADDR_DIV;
drp_di    <= div_frac;
if(ssc_en && drp_rdy) drp_we <= 1;  // 每个 clk_i 周期尝试
写一次
endendmodule
