module jtag_bypass (
input  logic tck,
input  logic trst_n,
input  logic shift_dr,
input  logic clock_dr,
input  logic update_dr,
input  logic tdi,
output logic tdo
);
logic bypass_reg, bypass_out;
// 移位寄存器
always_ff @(posedge tck or negedge trst_n) begin
if (!trst_n)        bypass_reg <= 1'b0;
else if (clock_dr)  bypass_reg <= shift_dr ? tdi : bypass_reg;
end
// 更新寄存器（可选，若需并行锁存）

always_ff @(negedge tck or negedge trst_n) begin
if (!trst_n)        bypass_out <= 1'b0;
else if (update_dr) bypass_out <= bypass_reg;
end
