input  wire [DW-1:0] d,
output wire [DW-1:0] q
);
// 三份冗余寄存器
reg [DW-1:0] r0, r1, r2;
always @(posedge clk or negedge rst_n) begin
if (!rst_n) begin
r0 <= '0; r1 <= '0; r2 <= '0;
end else if (en) begin
r0 <= d; r1 <= d; r2 <= d;
endend
// 逐位多数表决
wire [DW-1:0] q_voted;
genvar i;
generate
for (i = 0; i < DW; i = i + 1) begin : vote_bit
assign q_voted[i] = (r0[i] & r1[i]) | (r0[i] & r
2[i]) | (r1[i] & r2[i]);
endendgenerate
assign q = q_voted;
endmodule
```

2. 面积评估：三份寄存器 + 投票器，面积约 3.2×，在 28 nm 工艺下等效门数 <3 kGE，对 100 kGE 级子系统可接受。
3. 时序收敛：投票器是纯组合，插入在 Q 端之前，需设 set_false_path 从冗余寄存器到投票器，防止综合器过度优化；同时用 pipeline 寄存器 隔离关键路径，保证 Fmax 损失 <3%。
4. FIT 重算：按 MIL-HDBK-217F 和 SMIC 提供的基础 FIT 率，单寄存器 F IT=12，TMR 后仅当任意两份同时失效才出错，等效 FIT ≈ 3×12²×10⁻⁹ =
4.3×10⁻⁷，即 0.43，远低于目标 10，满足车规。
5. 验证闭环： 用 VCS UVM 在测试层随机翻转任意一份寄存器，检查输出是否纠正； 后端用 TetraMAX 跑 ATPG，确保冗余逻辑未被工具当成冗余逻辑优化掉； 最终 Sign-off 报告里把 FIT 结果写进《可靠性确认书》，提交给客户。

// 多数表决器（TMR 投票器） // 可综合、参数化、无锁存器

```systemverilog
module tmr_voter #(
parameter WIDTH = 1   // 默认 1 bit，可投票 32/64 bit 总线
)(
input  wire [WIDTH-1:0] a,
input  wire [WIDTH-1:0] b,
input  wire [WIDTH-1:0] c,
output wire [WIDTH-1:0] vote_out
);
// 纯组合逻辑，逐位多数表决
assign vote_out = (a & b) | (b & c) | (c & a);

endmodule
```

关键点说明使用按位操作，因此 WIDTH 可任意扩宽，无需循环生成； 没有时钟、没有复位，综合结果仅为三级门延迟； 若数据总线超 64 bit，建议在综合脚本里加 set_max_fanout 32，防止扇出过大。

