parameter DW = 16,          // 数据位宽
parameter COEFF_DW = 18     // 系数位宽
)(
input               clk,        // fs 时钟
input               rst_n,
input               valid_in,   // 输入有效
input  signed [DW-1:0]  din,
output reg              valid_out,
output signed [DW+COEFF_DW+2-1:0] dout // 全精度输出
);

// 7 阶半带系数（量化到 18 bit，仅奇数位置非零）
localparam signed [COEFF_DW-1:0] C1 = 18'h02000;  // 0.125
localparam signed [COEFF_DW-1:0] C3 = 18'hFC000;  // -0.875
对称后
localparam signed [COEFF_DW-1:0] C5 = C3;
localparam signed [COEFF_DW-1:0] C7 = C1;
// 移位寄存器，深度 7
reg signed [DW-1:0] sr [0:7];
always @(posedge clk or negedge rst_n) begin
if(!rst_n) begin
sr[0] <= '0;
sr[1] <= '0; sr[2] <= '0; sr[3] <= '0;
sr[4] <= '0; sr[5] <= '0; sr[6] <= '0; sr[7] <= '0;
end
else if(valid_in) begin
sr[0] <= din;
sr[1] <= sr[0]; sr[2] <= sr[1]; sr[3] <= sr[2];
sr[4] <= sr[3]; sr[5] <= sr[4]; sr[6] <= sr[5]; sr
[7] <= sr[6];
endend
// 预加：利用对称性
wire signed [DW:0] pre0 = {sr[0][DW-1], sr[0]} + {sr[7][DW-
1], sr[7]};
wire signed [DW:0] pre1 = {sr[2][DW-1], sr[2]} + {sr[5][DW-
1], sr[5]};
// 乘法器复用：分时计算奇数支路
reg        mul_phase;
reg signed [DW+COEFF_DW:0] mul_out;
always @(posedge clk or negedge rst_n) begin
if(!rst_n) mul_phase <= 1'b0;
else if(valid_in) mul_phase <= ~mul_phase;
end
always @(*) begin
case(mul_phase)
1'b0: mul_out = pre0 * C1;
1'b1: mul_out = pre1 * C3;
endcaseend
// 累加器：两个周期完成一次卷积
reg signed [DW+COEFF_DW+2:0] acc;
always @(posedge clk or negedge rst_n) begin
if(!rst_n) acc <= '0;
else if(valid_in & mul_phase==1'b0) acc <= mul_out;
// 第一拍
else if(valid_in & mul_phase==1'b1) acc <= acc + mul_ou
t;    // 第二拍
end
// 抽取：每两个周期输出一次
always @(posedge clk or negedge rst_n) begin

if(!rst_n) valid_out <= 1'b0;
else        valid_out <= (valid_in & mul_phase==1'b1);
end
always @(posedge clk) begin
if(valid_out) dout <= acc;
endendmodule
关键技巧回顾：
零系数直接省略，只在奇数位置做乘法；
系数对称→pre-add，乘法器再减半；
利用“先↓2”思想，内部逻辑跑 fs/2，省功耗；
输出 valid_out 与数据严格对齐，下游 FIFO 可直接收数，无需额外跨时
钟。
```

