wire             tick;
// 1. 模 ratio 计数器，0 时产生 tick
assign tick = (cnt == {CNT_W{1'b0}});
always @(posedge clk or negedge rst_n) begin
if (!rst_n)
cnt <= {CNT_W{1'b0}};
else if (valid_in && ready_in) begin
if (cnt == ratio - 1'b1)
cnt <= {CNT_W{1'b0}};
else
cnt <= cnt + 1'b1;
endend
// 2. 输出寄存器，仅在 tick 时更新
always @(posedge clk or negedge rst_n) begin
if (!rst_n) begin
data_out  <= {DW{1'b0}};
valid_out <= 1'b0;
end
else begin
if (tick && valid_in && ready_in) begin
data_out  <= data_in;
valid_out <= 1'b1;
end
else if (ready_out) begin
valid_out <= 1'b0;
endendend
// 3. 反压逻辑：只要本级能接收，就拉高 ready_in
assign ready_in = !valid_out || ready_out;
endmodule
```

关键细节说明 ratio 为运行时输入，位宽比 $clog2(DMAX)$ 多 1 位，支持 1~DMAX 全范围； tick 脉冲周期 = ratio，保证输出采样率精确； ready_in 实现反压，当 downstream 未准备好时，upstream 自动停流； 整个路径无组合环，可插入流水线寄存器以满足高频需求；

综合后仅消耗一个加法器 + 两个寄存器阵列，面积与固定抽取器几乎相同。

