else begin
for (k = 0; k < PORT_N; k = k + 1) begin

case (state[k])
IDLE: begin
if (fault[k]) begin
state[k]     <= SWITCH;
nxt_sel[k]   <= nxt_port[k];  // 查表得下
一跳
endend
SWITCH: begin  // 1 cycle 完成切换
active_path[k] <= (nxt_sel[k] < PORT_N) ? nx
t_sel[k] : k;
state[k]       <= IDLE;
end
default: state[k] <= IDLE;
endcaseendendend
// 4. 无 glitch 多路选择
reg [FIFO_DW-1:0] data_out;
reg               out_vld;
always @(posedge clk) begin
out_vld <= data_vld[active_path[0]];  // 单端口示例
data_out <= data_in[active_path[0]];
end
