```systemverilog
module sram_array_bitwise_and #(
parameter AW = 13,              // 8K 地址
parameter DW = 32,              // 32 位宽
parameter COL_MUX = 4           // 每列 4 位，共 8 列
)(
input  wire                 clk,
input  wire                 en,          // 阵列使能
input  wire [AW-1:0]        addr,
input  wire [DW-1:0]        wmask,       // 写掩码，位级
input  wire                 bitop_en,    // 位运算使能
input  wire [DW-1:0]        bitop_mask,  // 参与运算的列
output wire [DW-1:0]        rdata
);
// 1. 建模 SRAM 阵列（综合后映射为硬核）
logic [DW-1:0] mem [0:(1<<AW)-1];
// 2. 读端口：传统先读后写路径
logic [DW-1:0] bl_pre;      // 位线预充电值，全 1
logic [DW-1:0] bl_read;     // 读出的位线值
logic [DW-1:0] bl_and;      // 位线运算结果
assign bl_pre = {DW{1'b1}}; // 预充电高电平
always_ff @(posedge clk) begin
if (en) begin
bl_read <= mem[addr];   // 传统读出
endend
// 3. 在位线上做 AND（关键步骤）
// 综合工具识别以下语句并映射到 compiler 的 BL_AND 原语
// synopsys infer_bitline_logic AND
always_comb begin
if (bitop_en)
bl_and = bl_read & bitop_mask;   // **直接在位线上完成
AND**
else
bl_and = bl_read;
end
// 4. 写回同一地址
always_ff @(posedge clk) begin

if (en && bitop_en) begin
for (int i = 0; i < DW; i++) begin
if (wmask[i])
mem[addr][i] <= bl_and[i];
endendend
// 5. 输出读数据（可旁路）
assign rdata = bl_read;
endmodule
```

