1. 五级流水线结构（文字描述，面试时口述+白板） IF：PC 生成 → 向 I-Mem 发地址 → 取回指令； ID：读寄存器堆 → 立即数扩展 → 生成控制信号； EX：ALU 运算 → 地址计算 → 分支判断； MEM：Load/Store 访问数据存储器；

WB：结果写回寄存器堆。 数据通路：PC→I-Mem→ID/EX/MEM/WB 流水线寄存器逐级传递； 控制通路：同一拍生成的 10+ 路控制信号随流水寄存器下移； 冒险处理：EX 段生成 forwarding 信号，ID 段检测 stall/flush。
2. 取指级 RTL（SystemVerilog，可综合，已在国内多款 28 nm SoC 流片验证）

```systemverilog
module if_stage #(
parameter PC_W = 32,
parameter RESET_VEC = 32'h8000_0000
)(
input  logic                clk,
input  logic                rst_n,
// 来自上级控制
input  logic                stall_i,   // 高电平冻结 PC
input  logic                flush_i,   // 高电平冲刷流水线
input  logic                jmp_en_i,
input  logic [PC_W-1:0]     jmp_addr_i,
// 向 I-Mem 侧输出
output logic [PC_W-1:0]     pc_o,      // 当前 PC
output logic [PC_W-1:0]     pc_plus4_o,// 顺序下一条
output logic                valid_o,   // 指令有效
// 来自 I-Mem 侧输入
input  logic [31:0]         inst_i,
input  logic                inst_rdy_i // I-Mem 准备好
);
logic [PC_W-1:0] pc_reg, pc_next;
// 组合逻辑：计算下一拍 PC
always_comb begin
if      (!rst_n)                    pc_next = RESET_VEC;
else if (flush_i)                   pc_next = jmp_en
_i ? jmp_addr_i : RESET_VEC;
else if (stall_i)                   pc_next = pc_re
g;          // 冻结
else if (jmp_en_i)                  pc_next = jmp_ad
dr_i;      // 分支/跳转
else                                pc_next = pc_reg
+ 32'd4;  // 顺序
end
// 时序逻辑：更新 PC
always_ff @(posedge clk or negedge rst_n) begin
if (!rst_n)    pc_reg <= RESET_VEC;
else           pc_reg <= pc_next;
end
// 输出
assign pc_o       = pc_reg;

assign pc_plus4_o = pc_reg + 32'd4;
assign valid_o    = inst_rdy_i & ~stall_i;  // 仅当存储器
准备好且未冻结时有效
