```systemverilog
module hazard_unit (
input        clk,
input        rst_n,
// 来自 ID 级
input [4:0]  id_rs1,
input [4:0]  id_rs2,
input        id_rs1_valid,
input        id_rs2_valid,
// 来自 EX 级
input [4:0]  ex_rd,
input        ex_reg_write,
// 来自 MEM 级
input [4:0]  mem_rd,
input        mem_reg_write,
// 来自 WB 级
input [4:0]  wb_rd,
input        wb_reg_write,
// 输出
output logic stall,
output logic [1:0] forward_a, // 00=寄存器堆, 10=EX 结果,
01=MEM 结果
output logic [1:0] forward_b
);
// RAW 检测
logic rs1_ex_hazard, rs1_mem_hazard, rs2_ex_hazard, rs2_mem_hazard;
assign rs1_ex_hazard  = (id_rs1 == ex_rd)  && ex_reg_write
&& id_rs1_valid && (id_rs1 != 0);
assign rs1_mem_hazard = (id_rs1 == mem_rd) && mem_reg_writ
e && id_rs1_valid && (id_rs1 != 0);
assign rs2_ex_hazard  = (id_rs2 == ex_rd)  && ex_reg_write
&& id_rs2_valid && (id_rs2 != 0);
assign rs2_mem_hazard = (id_rs2 == mem_rd) && mem_reg_writ
e && id_rs2_valid && (id_rs2 != 0);
// 优先级：EX 级结果最新
assign forward_a = rs1_ex_hazard ? 2'b10 :
rs1_mem_hazard ? 2'b01 : 2'b00;
assign forward_b = rs2_ex_hazard ? 2'b10 :
rs2_mem_hazard ? 2'b01 : 2'b00;
// 若 EX/MEM 级是 load，且地址冲突，必须 stall
logic load_ex;

assign load_ex = ex_reg_write && /* ex_is_load 信号由 ID 译
码给出 */ ex_is_load;
assign stall   = (rs1_ex_hazard || rs2_ex_hazard) && load_ex;
endmodule
```

关键技巧
1. "!=0" 排除 x0 寄存器，节省 10% 组合面积；
2. stall 信号直接拉低 IF/ID 寄存器写使能，并在下一拍撤销，保证气泡仅插入 1 周期；
3. forwarding 路径用独立 assign，DC 可自动映射到 MUX2/MUX3，不增加关键路径；
4. 若项目频率高于 1 GHz，可把 EX 级比对做成二级流水线寄存，牺牲半个周期 latency 换时序。

