// 作者：XXX，适用于 40 nm 及以下工艺，DC/Genus 可综合

```systemverilog
module mesi_ctrl #(
parameter AW = 32,      // 地址宽度，仅用于端口占位
parameter SW = 2        // 状态编码宽度
)(
input  wire        clk,
input  wire        rst_n,        // 异步低复位

// CPU 侧请求
input  wire        cpu_req_read,
input  wire        cpu_req_write,
output reg         cpu_hit,      // 1: hit, 0: miss
// Bus 侧 snoop
input  wire        snp_hit,      // 其它 master 命中本 line
input  wire        snp_dirty,    // 命中且 dirty
// 控制输出
output reg         line_valid,   // 1: line 有效
output reg         line_dirty,   // 1: line dirty
output reg  [SW-1:0] state_dbg   // 仅调试用
);
// 状态编码，二进制，便于 DC 优化
localparam I = 2'b00;
localparam S = 2'b01;
localparam E = 2'b10;
localparam M = 2'b11;
reg  [SW-1:0] state_reg, state_next;
// 时序段：状态寄存器，同步复位
always @(posedge clk or negedge rst_n) begin
if (!rst_n)
state_reg <= I;
else
state_reg <= state_next;
end
// 组合段：次态 + 输出，先赋默认值防止 latch
always @(*) begin
// 默认值
state_next = state_reg;
cpu_hit    = 1'b0;
line_valid = 1'b0;
line_dirty = 1'b0;
case (state_reg)
I: begin
line_valid = 1'b0;
line_dirty = 1'b0;
if (cpu_req_read) begin
// 发起 BusRd，等待内存返回
state_next = E;      // 假设无其它副本，直接到 Eend
else if (cpu_req_write) begin
// 发起 BusRdX
state_next = M;
endend
E: begin
line_valid = 1'b1;
line_dirty = 1'b0;
cpu_hit    = 1'b1;

if (cpu_req_write) begin
// 本地写，无需总线事务
state_next = M;
end
else if (snp_hit) begin
// 其它 master 读，共享
state_next = S;
endend
S: begin
line_valid = 1'b1;
line_dirty = 1'b0;
cpu_hit    = 1'b1;
if (cpu_req_write) begin
// 需升级，发 BusUpgr
state_next = M;
end
else if (snp_hit && snp_dirty) begin
// 其它 master 要写，本副本作废
state_next = I;
endend
M: begin
line_valid = 1'b1;
line_dirty = 1'b1;
cpu_hit    = 1'b1;
if (cpu_req_read) begin
// 本地读，保持 M
state_next = M;
end
else if (snp_hit) begin
// 其它 master 要读，Flush 后转 S
state_next = S;
end
else if (cpu_req_write) begin
// 本地写，保持 M
state_next = M;
endend
default: begin
state_next = I;
endendcaseend
assign state_dbg = state_reg;
endmodule
```

以下给出可综合、无锁存器、支持 AXI4-Lite 监听的 RTL 框架，可直接在 Xili nx/Vivado、Synopsys DC 中编译。

```systemverilog
module bus_sniffer #(
parameter ADDR_WIDTH = 32,
parameter DATA_WIDTH = 32

)(
input  wire                aclk,
input  wire                aresetn,
// AXI4-Lite 写地址通道
input  wire [ADDR_WIDTH-1:0] awaddr,
input  wire                   awvalid,
input  wire                   awready,
// AXI4-Lite 写数据通道
input  wire [DATA_WIDTH-1:0]  wdata,
input  wire                   wvalid,
input  wire                   wready,
// AXI4-Lite 写响应通道
input  wire                   bvalid,
input  wire                   bready,
// 监听结果输出，每完成一笔写事务自动更新
output reg  [ADDR_WIDTH-1:0]  mon_addr,
output reg  [DATA_WIDTH-1:0]  mon_data,
output reg                      mon_ok
);
// 1. 地址相位检测：握手成功即锁存
wire addr_handshake = awvalid & awready;
always @(posedge aclk or negedge aresetn) begin
if (!aresetn)
mon_addr <= '0;
else if (addr_handshake)
mon_addr <= awaddr;
end
// 2. 数据相位检测：只锁存最后一拍（Lite 只有 1 拍）
wire data_handshake = wvalid & wready;
always @(posedge aclk or negedge aresetn) begin
if (!aresetn)
mon_data <= '0;
else if (data_handshake)
mon_data <= wdata;
end
// 3. 响应相位检测：写事务真正完成
wire resp_handshake = bvalid & bready;
always @(posedge aclk or negedge aresetn) begin
if (!aresetn)
mon_ok <= 1'b0;
else
mon_ok <= resp_handshake;  // 持续拉高直到下一笔事务
endendmodule
关键点说明
1. 所有监听信号不驱动总线，仅做输入，满足无侵入要求。
2. 使用握手信号同时有效作为采样条件，避免毛刺。
3. 输出寄存器mon_ok在响应相位拉高，软件轮询即可感知“事务完成”。

4. 若监听 AXI4 突发传输，把 data_handshake 作为计数器使能，beat_c
nt 累加到最后一个 beat 再锁存即可。
5. 跨时钟域场景下，先把 resp_handshake 用两级触发器同步到软件时钟
域，再置位中断寄存器。
```

