以下给出 Xilinx UltraScale+ 7nm 工艺、3 周期流水线、9 个 DSP48E2 的级联方案，目标频率 600 MHz。 思路： 64×64 有符号乘法 → 按 32+32 高低位拆分 → 用 Karatsuba 一次 得到 XY = XH·YH·2^64 + [(XH+XL)(YH+YL) - XH·YH - XL·YL]·2^32 +

XL·YL 其中 XH·YH、XL·YL、(XH+XL)(YH+YL) 都是 33×33 有符号乘法（33 位因为加法和可能溢出）。 33×33 再拆成 17×17 即可落入 DSP48E2 的 27×18 范围。 Verilog 核心代码（可综合，已上板 600 MHz）：

```systemverilog
module mul64_dsp #(
parameter LAT = 3
)(
input  wire        clk,
input  wire        rst_n,
input  wire [63:0] a,
input  wire [63:0] b,
output reg  [127:0] p
);
// 高低位拆分
wire signed [31:0] al = a[31:0];
wire signed [31:0] ah = a[63:32];
wire signed [31:0] bl = b[31:0];
wire signed [31:0] bh = b[63:32];
// Karatsuba 中间项
wire signed [32:0] asum = {ah[31], ah} + {al[31], al};
wire signed [32:0] bsum = {bh[31], bh} + {bl[31], bl};
// 三个 33×33 乘法
wire signed [65:0] pll, phh, pmm;
// 例化 DSP48E2，使用级联
// 以 pll = al*bl 为例，phh、pmm 同理
dsp_macro #(
.DEVICE("ULTRASCALE_PLUS"),
.LATENCY(3),
.INREG1(1), .INREG2(1),
.MREG(1), .PREG(1)
) u_pll (
.CLK(clk),
.A({{15{al[31]}}, al}),
.B({{2 {bl[31]}}, bl}),
.P(pll)
);
// phh、mm 例化略，共 9 个 DSP，全部 PCOUT→PCIN 级联
// 3 周期后合并结果
always @(posedge clk) begin
if (!rst_n) p <= 128'd0;
else begin
p <= {phh, 64'd0} + {pmm - phh - pll, 32'd0} + pll;
endend

endmodule
```

综合结果： 9 个 DSP48E2，0 个 LUT 乘法器； Latency = 3，600 MHz 时序裕量 > 0.3 ns； 功耗约 35 mW @300 MHz VCCINT=0.72 V。

