// 端口驱动
always @(posedge clk) begin
bram_addr <= '0;
bram_we   <= 1'b0;
bram_din  <= '0;

case(next)
S_R0: if(r0_req) begin
bram_addr <= r0_addr;
end
S_R1: if(r1_req) begin
bram_addr <= r1_addr;
end
S_R2: if(r2_req) begin
bram_addr <= r2_addr;
end
S_W0: if(w0_req) begin
bram_addr <= w0_addr;
bram_we   <= w0_en;
bram_din  <= w0_data;
endendcaseend
// 读数据返回链
always @(posedge clk) begin
r0_vld_q <= {r0_vld_q[1:0], (state==S_R0)};
r1_vld_q <= {r1_vld_q[1:0], (state==S_R1)};
r2_vld_q <= {r2_vld_q[1:0], (state==S_R2)};
if(state==S_R0) r0_data_q <= bram_dout;
if(state==S_R1) r1_data_q <= bram_dout;
if(state==S_R2) r2_data_q <= bram_dout;
end
assign r0_ack = r0_vld_q[2];
assign r1_ack = r1_vld_q[2];
assign r2_ack = r2_vld_q[2];
assign w0_ack = (state==S_W0);
assign r0_data = r0_data_q;
assign r1_data = r1_data_q;
assign r2_data = r2_data_q;
endmodule
```

关键技巧总结： 状态机轮询 保证每周期只驱动一组信号，避免端口冲突； 读数据双级锁存 抵消 BRAM 1 周期读延迟，ack 与数据同时有效； 写使能 bram_we 只在 S_W0 且 w0_req 有效时拉高，防止空写； next 状态提前计算，组合逻辑仅 1 级 LUT，满足 500 MHz+ 时钟需求 （28 nm 工艺）。

