关键点：req_a 必须保持至少三个 clk_b 周期，确保 req_b 能采到并回传 ac k，否则用脉冲展宽或异步 FIFO。 场景 B：多比特数据跨时钟域采用异步 FIFO，核心代码片段：
// 写侧
assign wr_en = wr_valid & ~full;
always @(posedge wr_clk)
if (wr_en) mem[wr_ptr_gray[ADDR_W-1:0]] <= wr_data;
// 读侧
assign rd_en = rd_ready & ~empty;
always @(posedge rd_clk)
if (rd_en) rd_data <= mem[rd_ptr_gray[ADDR_W-1:0]];
// 格雷码指针同步
always @(posedge rd_clk) wr_ptr_gray_sync <= wr_ptr_gray;
assign empty_val = (wr_ptr_gray_sync == rd_ptr_gray);
