分“RTL 预防—>综合约束—>布局实施—>验证签核”四步作答，可直接用于面试场景：
1. RTL 预防对高扇出时钟使能、复位链，采用 Balanced Tree 结构，避免综合后局部密度 > 85%，从源头减少跨色边界几率。 例：

// 不推荐：高密度复位
assign rst_n = &rst_chain;
// 推荐：插入两级缓冲，降低局部密度
assign rst_n = rst_buf1 & rst_buf2;
2. 综合约束在 .sdc 中增加 Color Budget： set_color_budget -color 0 -max_util 0.45 [get_cells *u_d atapath*] set_color_budget -color 1 -max_util 0.45 [get_cells *u_c trl*] 国内 12 nm 项目实测，可把冲突密度从 1.2 k/cmm² 降到 0.3 k/cmm²。
3. 布局实施运行 place_opt 前，先执行 check_color_legality -pre_p lace，若报告 Color Anchor Missing，则在内存条/PCIe 宏单元边界手动 instantiate Color Anchor Filler（SMIC 14 nm 库名 FILLC DA*）。 对 SRAM 拼接，采用 Checkerboard Placement：相邻 SRAM 旋转 180°，利用 Foundry 预着色边界互补，消除拐角冲突。 设置 Color Keep-Out： setColorKeepOut -layer M2 -width 0.08 -offset 0.04
-region [get_cells *pll*]
4. 验证签核使用 Calibre MP 或 ICV DPT 做最终分解，若出现 Same-Color Spacin g Violation，优先在布局阶段用 Color Swapping 修复；若仍失败，则回到 Step1 调整 RTL 密度，绝不拖到绕线后期。

下面给出可综合 RTL 框架（40 nm 工艺，单时钟域，APB 配置接口），重点突出温度采样、门限判决、降频状态机、无毛刺切换四段，面试时可手写关键片段并口述其余。

```systemverilog
module throttling_ctrl #(
parameter ADC_WIDTH = 10,
parameter TEMP_TH   = 10'd580  // 85 °C 对应 ADC 码值，可寄

存器配置
)(
input  wire               clk,      // 系统时钟 100 MHz
input  wire               rst_n,
input  wire [ADC_WIDTH-1:0] temp_raw, // 来自传感器，异步
input  wire               temp_valid,
output reg                clk_en,   // 输出到时钟门控
output reg                pll_cfg   // 输出到 PLL 重配端口
);
// 1. 跨时钟同步 + 滑动平均
reg [ADC_WIDTH-1:0] temp_q1, temp_q2;
always @(posedge clk or negedge rst_n) begin
if (!rst_n) begin temp_q1 <= '0; temp_q2 <= '0; end
else begin temp_q1 <= temp_raw; temp_q2 <= temp_q1; endend
reg [ADC_WIDTH-1:0] avg_reg [0:3];
reg [2:0] avg_ptr;
always @(posedge clk) begin
if (temp_valid) begin
avg_ptr <= avg_ptr + 1;
avg_reg[avg_ptr] <= temp_q2;
endend
wire [ADC_WIDTH+1:0] avg_sum = avg_reg[0]+avg_reg[1]+avg_reg
[2]+avg_reg[3];
wire [ADC_WIDTH-1:0] temp_filt = avg_sum[ADC_WIDTH+1:2]; //
除以4
// 2. 门限比较 + 去抖
reg hot_raw, hot_sync;
always @(posedge clk) hot_raw <= (temp_filt > TEMP_TH);
reg [3:0] hot_cnt;
always @(posedge clk) begin
if (hot_raw)  hot_cnt <= (hot_cnt==4'd15) ? 4'd15 : hot_
cnt+1;
else          hot_cnt <= (hot_cnt==4'd0)  ? 4'd0  : hot_cnt-1;
end
always @(posedge clk) hot_sync <= (hot_cnt > 4'd12); // 连续1
3次高温才置位
// 3. 降频状态机
localparam IDLE=2'd0, DEGRADE=2'd1, HOLD=2'd2, RECOVER=2'd3;
reg [1:0] state, next;
reg [15:0] cool_timer; // 1 ms @100 MHz 需 100 000 周期，简化为
16'd50000
always @(posedge clk or negedge rst_n) begin
if (!rst_n) state <= IDLE;
else        state <= next;
end
always @(*) begin
next = state;
case (state)
IDLE:    if (hot_sync) next = DEGRADE;
DEGRADE: next = HOLD;

HOLD:    if (!hot_sync) next = RECOVER;
RECOVER: if (cool_timer==16'd0) next = IDLE;
endcaseend
always @(posedge clk) begin
if (state==RECOVER && !hot_sync)
cool_timer <= cool_timer - 1'b1;
else if (state!=RECOVER)
cool_timer <= 16'd50000;
end
// 4. 无毛刺时钟使能
always @(posedge clk) begin
clk_en <= (state==IDLE || state==RECOVER);
end
// 若用 PLL 重配，此处改为配置码输出
always @(posedge clk) begin
pll_cfg <= (state==DEGRADE || state==HOLD);
endendmodule
关键点解释（面试口述）：
温度滤波：滑动平均长度 4，兼顾噪声抑制与响应速度，约 40 µs 延迟。
门限去抖：12/16 投票，防止 85 °C 临界抖动导致频率抖动。
状态机：DEGRADE 状态单周期脉冲，保证 PLL 配置只触发一次；RECO
VER 需80 °C 以下且 50000 周期才升频，避免热振荡。
时钟门控：clk_en 直接驱动集成时钟门控单元(ICG)，综合工具可识别为C
G cell，功耗最优。
可扩展：TEMP_TH 通过 APB 寄存器在线改写，方便温箱校准；若支持
多域，可实例化多份模块，用Q-channel handshake 与 CPU 通信。
```

