module TSV_PHY #(
parameter R_TSV  = 25.0e-3,  // Ohm
parameter L_TSV  = 25.0e-12, // H
parameter C_OX   = 35.0e-15, // F
parameter C_SUB  = 55.0e-15, // F

parameter R_SUB  = 2.0e3     // Ohm
)(
input  logic in,
output logic out,
input  logic vss               // 衬底地
);
// 用分布式 RC 梯形网络，三段即可收敛
localparam int SEG = 3;
real r_seg = R_TSV / SEG;
real c_seg = C_OX  / SEG;
real l_seg = L_TSV / SEG;
real node [0:SEG];
real vout;
// 初始化
initial begin
foreach (node[i]) node[i] = 0.0;
vout = 0.0;
end
// 电阻+电感+电容
genvar k;
generate
for (k = 0; k < SEG; k++) begin : seg_loop
always @(node[k] or in) begin
#((r_seg+l_seg*1e-12)*1e-12) node[k+1] <= (n
ode[k] + in)/2.0;
endendendgenerate
// 耦合到衬底
always @(node[SEG] or vss) begin
#((C_SUB*R_SUB)*1e-15) vout <= (node[SEG] + vss)/2.
0;
end
assign out = vout;
endmodule
