output reg         overtemp_int
);
// 温度阈值比较
wire hot1 = temp_code >= THROTTLE1_TEMP;
wire hot2 = temp_code >= THROTTLE2_TEMP;
wire shut = temp_code >= SHUT_TEMP;
// 滞后恢复：只有温度低于“阈值-HYST”才允许升频
reg  hot1_d, hot2_d, shut_d;
always @(posedge clk_800M or negedge rst_n) begin
if(!rst_n) begin
hot1_d <= 1'b0;
hot2_d <= 1'b0;
shut_d <= 1'b0;
end else if(temp_valid) begin
hot1_d <= hot1;
hot2_d <= hot2;
shut_d <= shut;
endend
// 降频状态机：00=800M, 01=600M, 10=400M, 11=200M
reg [1:0] throttle_lvl, throttle_lvl_nxt;
always @* begin
throttle_lvl_nxt = throttle_lvl;
case(throttle_lvl)
2'b00: if(hot1)       throttle_lvl_nxt = 2'b01;
2'b01: if(hot2)       throttle_lvl_nxt = 2'b10;
else if(!hot1_d && temp_code < THROTTLE1_TEMP - HYST)
throttle_lvl_nxt = 2'b00;
2'b10: if(shut)       throttle_lvl_nxt = 2'b11;
else if(!hot2_d && temp_code < THROTTLE2_TEMP - HYST)
throttle_lvl_nxt = 2'b01;
2'b11: if(!shut_d && temp_code < SHUT_TEMP - HYST)
throttle_lvl_nxt = 2'b10;
endcaseend
always @(posedge clk_800M or negedge rst_n) begin
if(!rst_n)  throttle_lvl <= 2'b00;

else        throttle_lvl <= throttle_lvl_nxt;
end
// 无毛刺时钟切换器（Glitch-Free Clock Mux）
wire sel1, sel2;
assign sel1 = throttle_lvl[0];
assign sel2 = throttle_lvl[1];
// 使用厂商提供的 glitch-free 单元，这里用 RTL 模型示意
reg  clk_en1, clk_en2, clk_en3, clk_en4;
always @(posedge clk_800M or negedge rst_n) begin
if(!rst_n) begin
clk_en1 <= 1'b0; clk_en2 <= 1'b0; clk_en3 <= 1'b0; c
lk_en4 <= 1'b0;
end else begin
clk_en1 <= (throttle_lvl == 2'b00);
clk_en2 <= (throttle_lvl == 2'b01);
clk_en3 <= (throttle_lvl == 2'b10);
clk_en4 <= (throttle_lvl == 2'b11);
endend
// 时钟门控 + 或门合并（实际用库里的 CLKMUXGLITCHFREE）
assign clk_out = (clk_en1 & clk_800M) |
(clk_en2 & clk_600M) |
(clk_en3 & clk_400M) |
(clk_en4 & clk_200M);
// 中断与状态
always @(posedge clk_800M or negedge rst_n) begin
if(!rst_n) begin
throttle_active <= 1'b0;
overtemp_int    <= 1'b0;
end else begin
throttle_active <= (throttle_lvl != 2'b00);
overtemp_int    <= shut;
endendendmodule
关键设计要点：
温度码先经过两级寄存器同步再使用，避免亚稳态；
时钟切换采用使能信号先关后开，确保无毛刺；
滞后区间10 °C 防止频繁升降频；
