input        rst_n,
axi_if.slave axi_s,
output       irq_err
);
logic [63:0] wdata_q;
logic [31:0] crc_hw;
logic        crc_ok;
// 仅对 0x1000_0000 地址段启用 SM
assign sm_active = ENABLE_SM && (axi_s.awaddr == 32'h1000_0000);
always_ff @(posedge clk or negedge rst_n) begin
if (!rst_n) wdata_q <= '0;
else if (axi_s.wvalid && sm_active)
wdata_q <= axi_s.wdata;
end
// 实例化 CRC 校验
crc32_d64 u_crc (
.clk         (clk),
.rst_n       (rst_n),
.data        (wdata_q),
.data_valid  (axi_s.wvalid && sm_active),
.crc         (crc_hw)
);
