assign crc_ok = (axi_s.wuser[31:0] == crc_hw) || !sm_active;
// 写响应通道：校验失败返回 SLVERR
assign axi_s.bresp = crc_ok ? 2'b00 : 2'b10;
assign irq_err     = sm_active && !crc_ok;
// 安全属性断言，形式验证用
