1. C 层（bitflip_vpi.c） #include <vpi_user.h> #include <stdlib.h>
/* 入口：$bitflip("path", bit_idx); */
static int bitflip_calltf(char *userdata)
{
vpiHandle sys = vpi_handle(vpiSysTfCall, NULL);
vpiHandle argv = vpi_iterate(vpiArgument, sys);
/* 取路径字符串 */
vpiHandle pathH = vpi_scan(argv);
s_vpi_value pathVal; pathVal.format = vpiStringVal;
vpi_get_value(pathH, &pathVal);
/* 取比特索引 */
vpiHandle idxH  = vpi_scan(argv);
s_vpi_value idxVal; idxVal.format = vpiIntVal;
vpi_get_value(idxH, &idxVal);
int bit_idx = idxVal.value.integer;
/* 找到对象 */
vpiHandle obj = vpi_handle_by_name(pathVal.value.str, NULL);
if (!obj) {
vpi_printf("**ERROR: %s not found\n", pathVal.value.
str);
return 0;
}
/* 读当前值 */
s_vpi_value val; val.format = vpiVectorVal;
vpi_get_value(obj, &val);
int len = vpi_get(vpiSize, obj);
if (bit_idx >= len) {
vpi_printf("**ERROR: bit index %d >= width %d\n", bi
t_idx, len);
return 0;
}
/* 计算翻转 */
s_vpi_vecval *vec = val.value.vector;
int word = bit_idx / 32;
int mask = 1 << (bit_idx % 32);
vec[word].aval ^= mask;          /* 翻转 */ vec[word].bval &= ~mask;         /* 清除 X/Z */
/* 写回，使用 vpiNoDelay 立即生效 */
val.format = vpiVectorVal;
vpi_put_value(obj, &val, NULL, vpiNoDelay);
vpi_printf("[bitflip] %s[%d] flipped at time %llu\n", pathVal.value.str, bit_idx,
vpi_get(vpiTime, NULL));
return 0;
}

/* 注册 */
void register_bitflip()
{
s_vpi_systf_data tf = {0};
tf.type      = vpiSysTask;
tf.tfname    = "$bitflip";
tf.calltf    = bitflip_calltf;
tf.sizetf    = 0;
vpi_register_systf(&tf);
}
/* 仿真器自动调用 */
void (*vlog_startup_routines[])() = { register_bitflip, 0 };
