下面给出一段可综合、单时钟域、深度 512×128 bit 的 trace 循环覆盖模板， 重点突出“写指针自动回绕”与“覆盖最早数据”：

```systemverilog
module trace_circular #(
parameter DW = 128,              // 单条 trace 位宽
parameter AW = 9                 // 512 条目需 9 位地址
)(

input  wire        clk,
input  wire        rst_n,
input  wire        trace_vld,    // 上游 trace 有效
input  wire [DW-1:0] trace_data,
output wire [AW:0] wr_ptr        // 供软件观测，位宽 AW+1
);
// 1. 指针位宽 AW+1，MSB 用于空/满区分
reg [AW:0] wp;
wire       full;
wire       wr_en;
// 2. 双口 RAM 实例，可替换为 SRAM 宏
reg [DW-1:0] mem [0:(1<<AW)-1];
// 3. 写使能：上游有效即写，**不管满不满**，实现循环覆盖
assign wr_en = trace_vld;
always @(posedge clk) begin
if (!rst_n) begin
wp <= '0;
end
else if (wr_en) begin
mem[wp[AW-1:0]] <= trace_data;      // 低位地址写 RAM
wp              <= wp + 1'b1;       // **自动回绕**，
无需判断上限
endend
// 4. 输出当前写指针，软件按模运算解析
assign wr_ptr = wp;
endmodule
```

关键说明： wp 位宽 AW+1，当 wp 从 512 计到 1023 时，低位 wp[AW-1:0] 自动归零，实现硬件级循环覆盖； 不写满判断，保证 trace 永不丢失最新数据； 若需“冻结快照”，可在 overflow 时把当前 wp 锁存到寄存器，软件事后以该指针为基地址循环解析即可。

下面给出可综合的 Verilog 顶层框架，以 Xilinx FPGA 为例，实现 90° 与 180° 旋转脉宽校准。 思路：
1. PLL 产生 0°、90°、180°、270° 四相时钟；
2. 用 IDELAYE3 分别插在 90° 与 180° 路径；
3. Hogge 鉴相器比较 0°→90°、0°→180° 相位，输出 UP/DN；
4. SAR 状态机调整 tap 值，直到 UP=DN；
5. 校准完成后冻结 tap，进入周期性温漂补偿模式。
// 仅展示核心校准模块，省略 PLL 与 IDELAYE3 实例化

```systemverilog
module cal_90_180 #(
parameter TAP_WIDTH = 9,           // IDELAYE3 最大 512 tap
parameter SAR_LEN   = 9            // 2^9 = 512
)(
input  wire        clk0,           // 0° 时钟，来自 PLL
input  wire        clk90_raw,      // 未校准 90°
input  wire        clk180_raw,     // 未校准 180°
input  wire        rst_n,
output logic [TAP_WIDTH-1:0] tap90_q,
output logic [TAP_WIDTH-1:0] tap180_q,
output logic       cal_done
);
// 1. 延迟链输出
wire clk90_delay, clk180_delay;
// 2. Hogge 鉴相器输出
wire up90, dn90, up180, dn180;
// 3. SAR 寄存器
logic [SAR_LEN-1:0] sar90, sar180;
logic [2:0]         state;
localparam IDLE  = 3'd0,
INIT  = 3'd1,
WAIT  = 3'd2,
COMP  = 3'd3,
DONE  = 3'd4;
// 实例化 IDELAYE3（略）
// 实例化 Hogge PD（略）
// SAR 状态机
always @(posedge clk0 or negedge rst_n) begin
if (!rst_n) begin
sar90      <= '0;
sar180     <= '0;
state      <= IDLE;
cal_done   <= 0;
end else begin
case (state)
IDLE: begin
sar90  <= 1 << (SAR_LEN-1);   // 二分法中点

sar180 <= 1 << (SAR_LEN-1);
state  <= INIT;
end
INIT: begin
tap90_q  <= sar90;
tap180_q <= sar180;
state    <= WAIT;
end
WAIT: begin
// 等待延迟链稳定，2 个时钟足够
state <= COMP;
end
COMP: begin
// 根据 UP/DN 调整 SAR
if (up90 && !dn90) sar90 <= sar90 + (1 << (SAR_L
EN-1-state));
if (!up90 && dn90) sar90 <= sar90 - (1 << (SAR_L
EN-1-state));
if (up180 && !dn180) sar180 <= sar180 + (1 << (S
AR_LEN-1-state));
if (!up180 && dn180) sar180 <= sar180 - (1 << (S
AR_LEN-1-state));
if (state == COMP && sar90[TAP_WIDTH-1:0] == tap
90_q &&
sar180[TAP_WIDTH-1:0] == tap180_q)
state <= DONE;
else begin
tap90_q  <= sar90;
tap180_q <= sar180;
state    <= WAIT;
endend
DONE: cal_done <= 1;
endcaseendendendmodule
关键点说明：
延迟链控制字必须直接连到 IDELAYE3 的 CNTVALUEIN，不能用行为级
延迟；
SAR 状态机用组合比较 UP/DN，保证单周期收敛；
校准完成后，每 1 ms 重新触发一次 COMP 状态，补偿温漂；
tap 值跨时钟域输出时，加两级触发器，避免亚稳态传到 IDELAYE3。
```

