```systemverilog
module jesd204c_init_fsm #(
parameter LANES      = 4,           // 国内项目常用 4 lane
parameter MF_LEN     = 256,         // 多帧长度
parameter CRC_POLY   = 12'h80F,
localparam SYNC_S    = 3'd0,
localparam MAC_C     = 3'd1,
localparam PHY_B     = 3'd2,
localparam ERR_R     = 3'd3
)(
input  wire         line_clk,
input  wire         rx_reset,
input  wire [LANES-1:0] rx_char_is_k,
input  wire [LANES*8-1:0] rx_data,
output reg          rx_sync_done,
output reg          rx_ready
);
reg [2:0] state, nstate;
reg [10:0] mf_cnt;              // 256*8=2048 字节，需 11 位
reg [11:0] crc12;
reg [5:0]  good_s_cnt;          // 连续 /S/ 计数
reg [6:0]  blk_ok_cnt;          // 64b66b 块同步计数
wire s_char = (rx_data[7:0] == 8'hFB) && rx_char_is_k[0];
wire k_char = (rx_data[7:0] == 8'hBC) && rx_char_is_k[0];
always @(posedge line_clk) begin
if(rx_reset) begin
state <= SYNC_S;
mf_cnt <= 0;
crc12 <= 12'hFFF;
good_s_cnt <= 0;
blk_ok_cnt <= 0;
end else begin
state <= nstate;
mf_cnt <= (state==MAC_C && mf_cnt<MF_LEN*8-1) ? mf_c
nt+1 : 0;
crc12 <= next_crc12(rx_data[7:0], crc12);
endend
always @(*) begin
nstate = state;
case(state)
SYNC_S: begin
if(s_char && !k_char)
good_s_cnt = good_s_cnt + 1;
else
good_s_cnt = 0;
if(good_s_cnt >= 4)
nstate = MAC_C;
end

MAC_C: begin
if(mf_cnt == MF_LEN*8-1 && crc12 == 0)
nstate = PHY_B;
else if(crc12 != 0)
nstate = ERR_R;
end
PHY_B: begin
if(rx_data[1:0]==2'b10 || rx_data[1:0]==2'b01)
blk_ok_cnt = blk_ok_cnt + 1;
else
blk_ok_cnt = 0;
if(blk_ok_cnt >= 64)
nstate = SYNC_S; // 完成后回到 SYNC，等待上层释放
end
ERR_R: nstate = SYNC_S;
default: nstate = SYNC_S;
endcaseend
always @(posedge line_clk) begin
rx_sync_done <= (state == PHY_B && blk_ok_cnt >= 64);
rx_ready     <= (state == PHY_B);
end
function [11:0] next_crc12;
input [7:0] data;
input [11:0] crc;
integer i;
begin
next_crc12 = crc;
for(i=0;i<8;i=i+1) begin
if((next_crc12[11] ^ data[i]) == 1'b1)
next_crc12 = {next_crc12[10:0], 1'b0} ^ CRC_POLY;
else
next_crc12 = {next_crc12[10:0], 1'b0};
endendendfunctionendmodule
关键细节：
状态机只有 4 个状态，独热码面积在 28 nm 以上工艺反而大，这里用二
进制码；
mf_cnt 位宽 11 位，国内面试常挖坑问 10 位够不够，必须答“256*8=20
48，需 11 位”；
CRC-12 函数用纯组合逻辑，方便综合器优化成 3 级 LUT 链；
回到 SYNC_S 后 rx_sync_done 立即拉低，符合国内验证平台自检查机
制。
```

