parameter LANES      = 8,
parameter FIFO_DEPTH = 16,
parameter TAP_MAX    = 63
)(
input  wire                 ref_clk,      // 同源 312.5 MHz
input  wire                 phy_rdy,
input  wire [LANES-1:0]     rx_data,      // 已 8B10B 解
码，位宽 32 bit
input  wire [LANES-1:0]     rx_valid,
output wire [LANES-1:0][31:0] data_aligned,
output wire                 deskew_done,
// AXI-L 接口给软件
input  wire                 s_axil_clk,
input  wire [7:0]           s_axil_addr,
input  wire                 s_axil_wr,
input  wire [31:0]          s_axil_wdata,
output wire [31:0]          s_axil_rdata
);
// 1. 每 Lane 实例化异步 FIFO，写侧接 PHY 时钟，读侧接 ref_clk
genvar i;
generate
for (i = 0; i < LANES; i = i + 1) begin : gen_fifo
async_fifo #(
.DW(32),
.DEPTH(FIFO_DEPTH)
) u_fifo (
.wr_clk    ( phy_clk[i]      ),
.wr_data   ( rx_data[i]      ),
.wr_en     ( rx_valid[i]     ),
.rd_clk    ( ref_clk         ),
.rd_data   ( fifo_out[i]     ),
.rd_en     ( fifo_rd_en[i]   ),
.empty     ( fifo_empty[i]   )
);
endendgenerate
// 2. Deskew 控制状态机：SCAN → COMPARE → LOCK
localparam SCAN    = 2'b00;
localparam COMPARE = 2'b01;

localparam LOCK    = 2'b10;
reg [1:0] state;
reg [5:0] tap_cnt;          // 0~TAP_MAX
reg [LANES-1:0] eye_left, eye_right;
always @(posedge ref_clk) begin
if (!phy_rdy) begin
state <= SCAN;
tap_cnt <= 0;
end else case (state)
SCAN: begin
// 发送训练 Pattern K28.5，同时把当前 tap 值写入 per-Lane
Delay Line
tap_cnt <= tap_cnt + 1'b1;
if (tap_cnt == TAP_MAX) state <= COMPARE;
end
COMPARE: begin
// 统计每个 Lane 的 BER，记录 eye_left & eye_right
if (ber_ok) begin
eye_left  <= tap_cnt;
eye_right <= tap_cnt;
end
state <= LOCK;
end
LOCK: begin
// 把最优 tap 设成 (eye_left + eye_right)/2
// 同时拉高 deskew_done，通知 MAC 层可以开始传业务
endendcaseend
// 3. 输出对齐数据：FIFO 读使能同时拉高，保证所有 Lane 在同一拍吐出
assign fifo_rd_en = (state == LOCK) ? ~|fifo_empty : 1'b0;
assign data_aligned = fifo_out;
assign deskew_done = (state == LOCK);
// 4. AXI-L 寄存器：软件可读写 per-Lane tap 值，做在线微调
reg [5:0] tap_reg [0:LANES-1];
always @(posedge s_axil_clk) begin
if (s_axil_wr && s_axil_addr[7:0] < LANES*4)
tap_reg[s_axil_addr[7:2]] <= s_axil_wdata[5:0];
end
assign s_axil_rdata = {26'b0, tap_reg[s_axil_addr[7:2]]};
